func (a *adapter) SomeMutation(ctx context.Context, params planaddon.SomeMutationInput) (*planaddon.PlanAddon, error) {
  fn := func(ctx context.Context, a *adapter) (*planaddon.PlanAddon, error) {
    if err := params.Validate(); err != nil { return nil, fmt.Errorf("invalid params: %w", err) }
    row, err := a.db.PlanAddon.UpdateOneID(params.ID).Where(planaddondb.Namespace(params.Namespace)).SetSomeField(params.SomeField).Save(ctx)
    if err != nil {
      if entdb.IsNotFound(err) { return nil, planaddon.NewNotFoundError(planaddon.NotFoundErrorParams{Namespace: params.Namespace, ID: params.ID}) }
      return nil, err
    }
    return FromPlanAddonRow(*row)
  }
  return entutils.TransactingRepo[*planaddon.PlanAddon, *adapter](ctx, a, fn)
}

type (MyNewRequest = planaddon.MyNewInput; MyNewResponse = api.PlanAddon; MyNewParams struct{ PlanIDOrKey string }; MyNewHandler httptransport.HandlerWithArgs[MyNewRequest, MyNewResponse, MyNewParams])

func (h *handler) MyNew() MyNewHandler {
  return httptransport.NewHandlerWithArgs(
    func(ctx context.Context, r *http.Request, params MyNewParams) (MyNewRequest, error) {
      ns, err := h.resolveNamespace(ctx)
      if err != nil { return MyNewRequest{}, err }
      return MyNewRequest{NamespacedModel: models.NamespacedModel{Namespace: ns}, PlanIDOrKey: params.PlanIDOrKey}, nil
    }, /* op */, /* enc */)
}

func (s service) SomeMutation(ctx context.Context, params planaddon.SomeMutationInput) (*planaddon.PlanAddon, error) {
  fn := func(ctx context.Context) (*planaddon.PlanAddon, error) {
    if err := params.Validate(); err != nil { return nil, fmt.Errorf("invalid params: %w", err) }
    pa, err := s.adapter.SomeMutation(ctx, params)
    if err != nil {
      if notFound := &(planaddon.NotFoundError{}); errors.As(err, &notFound) { return nil, models.NewGenericNotFoundError(err) }
      return nil, err
    }
    if err = s.publisher.Publish(ctx, planaddon.NewPlanAddonUpdateEvent(ctx, pa)); err != nil { return nil, err }
    return pa, nil
  }
  return transaction.Run(ctx, s.adapter, fn)
}
